def get_db_session():
    global call_count
    call_count += 1
    print(f"Creating DB session (call #{call_count})")
    return {"session_id": call_count}

def get_user(db: dict = Depends(get_db_session)):
    return {"user": "Alice", "db_session": db["session_id"]}

